import React from 'react';
import '../styles/About.css';


const About = () => {
  return (
    <section id="about" style={styles.section}>
      <h2>About Me</h2>
      <p>
        I'm a passionate Nigerian developer currently completing my studies in 
        Computer Science and Engineering at GITAM University. I focus on building intelligent systems and elegant web applications.
      </p>
    </section>
  );
};

const styles = {
  section: {
    padding: '4rem 2rem', textAlign: 'center'
  }
};

export default About;
